var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"제5 방위선 함락 후, 72시간 경과","JPN":"第5防衛線陥落後、72時間経過","ENG":"72 hours after the fall of the 5th Defense Line","TWN":"第五防線淪陷後經過72小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제4 방위선, 외곽 지대","JPN":"人類統合防衛軍第4防衛線、外郭地帯","ENG":"Outskirts, United Humankind Defense Force's 4th Defense Line","TWN":"人類共同保衛軍第四防線郊區"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"이러지 마세요, 방위선 거주 구역은 이미 포화상태입니다.","JPN":"困ります、防衛線居住地域はすでに飽和状態なんです。","ENG":"Please stop. The Defense Line's residential area is already at max capacity.","TWN":"請別這樣，保衛軍居住區已經滿了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"제발, 제발 우리 아이만이라도 들어가게 해주세요!","JPN":"お願いします、どうかうちの子だけでも入れてください！","ENG":"Please, I beg you! At least let my child in!","TWN":"拜託拜託，起碼讓我們的孩子進去！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"하아, 이러면 곤란한데.","JPN":"はあ、まいったな。","ENG":"*Sigh* This won't end, will it?","TWN":"哀，這會讓我很為難的。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"이봐, 병사 막사 쪽이라면 아직 자리가 남았어, 일단 그쪽으로 안내해드리자고.","JPN":"おい、兵士用テントの方だったらまだ空きがある、とりあえずそこに案内しよう。","ENG":"Hey, there's some space in the barracks. Let her come in.","TWN":"這樣，士兵營區那邊還有位置，我先帶你們去那邊吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"감사합니다, 감사합니다!","JPN":"ありがとうございます、ありがとうございます！","ENG":"Thank you! Thank you so much!","TWN":"謝謝，謝謝！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아, 피난민 행렬이 끝나질 않네요.","JPN":"はぁ、避難民の行列にはキリがありませんね。","ENG":"*Sigh* The refugees just keep flooding in.","TWN":"哀哀，難民的隊伍根本看不見盡頭。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네. 방위군뿐만 아니라, 민간인들 역시 살아남기 위해 최선을 다하고 있어요.","JPN":"はい。防衛軍のみならず、民間人もやはり全力で生き残ろうとしています。","ENG":"Yes, it's not just the Defense Force, but the civilians are also doing their best to survive.","TWN":"是，不只是保衛軍，平民百姓也在努力地活下去。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"멸망을 앞둔 세계지만, 그럼에도 아직 이렇게나 많은 사람들이 이 땅에서 살아가고 있죠.","JPN":"滅亡に瀕した世界ですが、それでもまだこんなにもたくさんの人々がこの世界に生きています。","ENG":"Even though this world is bound to end, there are still a lot of people living here.","TWN":"雖然世界瀕臨滅亡，但還是有如此多的人活在這片土地上。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"군인으로서, 사람으로서 저는 저들을 외면할 수 없어요.","JPN":"私は軍人として、人として、彼らを見捨てることなんてできません。","ENG":"As a soldier and as another human being, I can't turn a blind eye to their situation.","TWN":"身為軍人，身而為人，我都不能不管他們。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니, 외면하지 않을 거예요.","JPN":"いいえ、見捨てたりしません。","ENG":"Or rather, I will not turn a blind eye.","TWN":"不，我不會不管他們。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"엇! 저기 군인 아가씨랑 그 옆에 칼 든 사람, 그 사람들이지? 네피림 사태 때!","JPN":"あっ！　あそこの軍人のお嬢さんと隣のナイフを持っている人、あれだよな？　ネフィリム事件のときの！","ENG":"Huh? That female soldier and the person wielding a sword, they're them, aren't they? The ones from the Nephil incident!","TWN":"嗯？那個軍人小姐和旁邊拿著刀的，是她們吧？諾菲力事件時的！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"정말이네! 저 두 사람, 크로스로드의 영웅들이잖아?","JPN":"本当だ！　あの二人って、クロスロードの英雄じゃないか？","ENG":"You're right! Those two are the heroes of Crossroads!","TWN":"真的欸！那二個人，不就是十字路口的英雄嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"아가씨들! 힘 내세요! 우리 아들도 방위군에서 목숨 걸고 싸우고 있습니다!","JPN":"お嬢さんたち！　頑張ってください！　うちの息子も防衛軍で命がけで戦っています！","ENG":"Hey! Keep up the good work! My son is also in the Defense Force fighting for our lives!","TWN":"二位小姐！加油！我們的兒子也在保衛軍拼命戰鬥著！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"네피림 사태 때처럼, 다시 한번 세계를 구해주세요!","JPN":"ネフィリム事件のときのように、もう一度私たちの世界を救ってください！","ENG":"Please save this world again like you did during the Nephil incident!","TWN":"請像諾菲力事件時一樣，再次拯救世界吧！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양, 외면하지 않을 거라면서 그렇게 어두운 표정을 짓고 계시면 어떡해요.","JPN":"カリンさん、見捨てたりしないとか言いながら、そんな暗い顔をしてたらダメじゃないですか。","ENG":"Karin, you say you're not going to turn a blind eye, but then why do you look so glum?","TWN":"卡琳，不是說過不會不管嘛，怎麼還擺出那副陰沉沉的表情。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자, 웃으면서 손이라도 흔들어 주자고요. 이렇게!","JPN":"さあ、笑顔で手でも振ってあげましょうよ。こうやって！","ENG":"C'mon. You have to smile and wave your hand! Like this!","TWN":"來，笑著揮揮手，像這樣！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇네요. 고마워요, 시영 씨.","JPN":"確かにそうですね。ありがとうございます。シノンさん。","ENG":"You're right. Thank you, Shiyoung.","TWN":"你說的沒錯，謝謝你，時雨。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그래도 거점 기지를 공격받았던 7지구 때와 달리 민간인 피해가 적어져서 다행이네요.","JPN":"でも拠点基地を襲われた第7地区よりは民間人被害が少なくてなによりですね。","ENG":"But at least the civilian casualties are minimal compared to when District 7's base was attacked.","TWN":"而且往好處想，幸虧事先發現到阿波利亞的目的，我們才能迅速採取對應措施。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그나마 빠른 대응이 가능했던 건, 사전에 아포리아의 목표를 밝혀낸 덕분이겠죠.","JPN":"まだ素早い対応ができたのは、事前にアポリアの目的を解明できたおかげでしょうね。","ENG":"The only reason we were able to respond quickly was because we found out beforehand what Aporia's objective was.","TWN":"與基地受到攻擊的第七區不同，至少這裡傷亡的平民變少了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. 그렇다고 이 사태가 네피림 때보다 낫다고 말할 수는 없어요.","JPN":"いいえ。被害が少なくても、今の状況がネフィリムのときよりマシだとは言えません。","ENG":"No. Even taking that into account, we can't say the situation is better than it was with the Nephil.","TWN":"不，現在的情況並不比諾菲力時期好。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"지금, 이 순간에도 아포리아는 착실히 네피림의 핵을 흡수하고 있을 테니까.","JPN":"今、この瞬間にもアポリアは着実にネフィリムの核を吸収しているでしょうから。","ENG":"Even at this very moment, Aporia is absorbing the cores of the Nephils.","TWN":"此時此刻，阿波利亞也在專心地吸收著諾菲力核心。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아포리아가 상위종이 되어버리기 전에, 늦기 전에 우리가 할 수 있는 일을 해야만 해요.","JPN":"アポリアが上位種になってしまう前に、手遅れになる前に私たちにできることをやらなければなりません。","ENG":"We must do what we can before it's too late and it turns into a high-category C.O.","TWN":"我們要在阿波利亞變得更高階之前，在一切都無法挽回之前，做我們力所能及的事情。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"우리가 할 수 있는 일이라고요?","JPN":"私たちにできることですか？","ENG":"What we can do?","TWN":"力所能及的事情？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"기억나세요, 시영 씨?","JPN":"覚えていますか、シノンさん？","ENG":"Don't you remember, Shiyoung?","TWN":"你還記得嗎，時雨？！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리가 처음 만났던 곳. 그리고 대령님이 네피림과 함께 떨어진 곳.","JPN":"私たちが最初に出会った場所。そして大佐がネフィリムと一緒に飛び込んだ場所。","ENG":"The place where we first met. And also where Colonel and the Nephil fell.","TWN":"我們第一次行動的地方，還有上校與諾菲力同歸於盡的地方。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이 곳 4지구에서 그리 멀리 떨어져 있지 않아요.","JPN":"この第4地区からそう離れていません。","ENG":"This place isn't that far from District 4.","TWN":"就在離第四區不遠處。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"만약, 그때 사용했던 차원 통로를 네피림 고치 주변에 설치할 수 있다면…….","JPN":"もし、あの時の次元通路をネフィリムの繭の周辺に設置することができたら……","ENG":"If we can open another dimensional passage near the Nephil cocoons like we did last time...","TWN":"如果，把當時使用的次元通道設置到諾菲力繭周圍……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"잠깐, 카린 양.","JPN":"待ってください、カリンさん。","ENG":"Wait, Karin.","TWN":"等等，卡琳？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"지금 크로스로드 작전을 한 번 더 시도하자는 거예요?","JPN":"クロスロード作戦をもう一度やろうっていうんですか？","ENG":"Are you saying you want to attempt Operation Crossroads again?","TWN":"你打算再進行一次十字路口作戰嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"무슨 말씀을 하는 거예요. 그때는 노란 머리 대령님도 있었고, 사이버캣도 있었잖아요.","JPN":"無理ですよ。あのときはあの金髪大佐もいましたし、サイバーキャットもいたから可能だったんです。","ENG":"You're not serious, are you? Because last time, we had Colonel Blonde and Cyber Cat with us.","TWN":"你不是認真的吧？那個時候我們還有金毛上校跟賽博貓。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"생환율은 둘째치더라도 작전 자체가 성립되지 않는다고요?","JPN":"生還率はともかく、作戦そのものが成立しませんよ？","ENG":"Forget the survival rate, the operation itself doesn't work, okay?","TWN":"先不說生還率，這個作戰本身能行得通嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그건 저도 알고 있지만…….","JPN":"それは私もわかっていますけど……","ENG":"I know that already, but...","TWN":"這我也知道……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"엑자일러의 도움 없이 아포리아를 처리할 방법은 이제 그 정도밖에 떠오르지 않아요.","JPN":"エグザイラーの助けなしに、アポリアを倒す方法はもうそれぐらいしか思いつかないんです。","ENG":"But I can't think of any other way to defeat Aporia without the Exile's help.","TWN":"但是在沒有流浪者的幫助下，要對付阿波利亞，我只能想到這一個辦法了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 그 방법조차, 아포리아가 5종이 되어버리는 순간 시도도 못 해보겠죠.","JPN":"そしてその方法も、アポリアが第5種になった瞬間、試すことすらできなくなってしまいます。","ENG":"But even that... We won't be able to attempt anything if Aporia becomes a Category 5.","TWN":"而且要是阿波利亞進化成了5類侵蝕體，我們就連嘗試的機會也沒有了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까 그 전에…….","JPN":"だからそうなる前に……","ENG":"So before that happens...","TWN":"所以，在那之前……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"그러니까 아무런 가능성도 없는 작전에 대원들과 스스로의 목숨을 밀어 넣겠다?","JPN":"だからって可能性が皆無の作戦に隊員たちと自らの命を投じるつもり？","ENG":"So you want to put your life and the other troops' lives at risk for an operation that has no chance of success?","TWN":"所以，要為了毫無可能性的作戰，把隊員們和自己推出去送死？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"레지날드 사령관님이 들었다면 혀를 차겠군. 카린 웡 소령?","JPN":"レジナルド司令官がそれを聞いたら、呆れてものも言えなかったでしょうね。カリン・ウォン少佐？","ENG":"Commander Reginald would scoff at your idea, don't you think, Major Karin Wong?","TWN":"多明尼克司令官聽到的話會狠狠地嘲笑你的，卡琳少校？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은 크로펠 전속 부관님?","JPN":"あなたは、クロペル専属副官？","ENG":"Adjutant Kropel?","TWN":"你是……婕娜副官？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"하지만 난 마음에 들었어.","JPN":"でも、私は気に入ったわ。","ENG":"But I like it.","TWN":"不過我很滿意。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그 괴물한테 한 방 먹여주고 싶은 건 너희만이 아니거든.","JPN":"あの化け物に一発食らわせてやりたいのは、あなたたちだけじゃないのよ。","ENG":"You're not the only one who wants to take that monster down.","TWN":"想狠狠給那怪物一拳的不是只有你們。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이건 대체……?","JPN":"これはいったい……？","ENG":"What is this...?","TWN":"這到底是……？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"전 세계를 뒤져, 찾아낸 <color=#ffd34c>고출력 빔 병기</color>야.","JPN":"この世界の隅々まで探して見つけた<color=#ffd34c>高出力ビーム兵器</color>よ。","ENG":"It's a <color=#ffd34c>high-powered beam weapon</color> we found while scouring all over the world.","TWN":"這是我搜遍全世界，找到的<color=#ffd34c>高輸出電波兵器</color>。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"제4 방위선에 있는 발전소를 직렬로 연결하면 함포 이상의 위력을 낼 수 있겠지.","JPN":"第4防衛線にある発電所に直接繋げれば、艦砲以上の威力を出せるはず。","ENG":"If we connect it directly to the 4th Defense Line's generator, it can output more power than a cannon on a ship.","TWN":"將第四防線的發電站串聯起來就能發出航母以上的威力。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"말도 안 돼. 이런 걸 가지고 있었으면서, 어째서 지금까지 모습을 감추고 있었던 겁니까?","JPN":"そんな。こんなものをお持ちなのに、なぜ今の今まで姿を隠されていたんですか？","ENG":"You can't be serious. Why have you been hiding something like this all this time?","TWN":"怎麼可能？要是有這種武器，為什麼到現在才拿出來？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은 네피림을 쓰러트리기 위한 아티팩트를 탐사하던 도중 실종되었다고 들었습니다만.","JPN":"ネフィリムを倒すためのアーティファクトを捜索している最中に行方不明になったと聞いておりましたが。","ENG":"Also, I heard that you were MIA while searching for Artifacts to defeat the Nephil.","TWN":"我聽說你為了打敗諾菲力，在前往探索人造神器的途中失蹤的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그래, 정확히 말하면 <color=#ffd34c>실종되었었지</color>.","JPN":"そうね。正確に言えば<color=#ffd34c>行方不明だった</color>。","ENG":"Yes. I was, technically, <color=#ffd34c>MIA</color>.","TWN":"沒錯，準確來說是<color=#ffd34c>失蹤過</color>。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"차원 폭풍에 휘말렸던 우리 부대가 이걸 찾아서 복귀했을 땐 사령관님은 이미 돌아가신 뒤였으니까.","JPN":"次元暴風に巻き込まれた私たちの部隊が、これを見つけ出して復帰したときには、すでに司令官はお亡くなりになっていたからね。","ENG":"My unit got sucked up in a dimensional storm, and by the time we returned, our commander had already passed away.","TWN":"我們部隊被捲入次元風暴，回歸時才聽到司令官已經犧牲的消息。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"듣기로는 네 직속 상관인 워커 대령도 그 작전에서 전사했다면서?","JPN":"あなたの直属の上官であるウォーカー大佐もあの作戦で戦死したと聞いているわよ？","ENG":"I also heard that your superior, Colonel Walker also died in that operation, no?","TWN":"我聽說你的直屬長官沃克上校也在那場作戰中戰死了？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네. 그렇습니다.","JPN":"はい。そのとおりです。","ENG":"Yes. That is correct.","TWN":"是的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"과정이야 어쨌든, 너는 상관의 원수를 갚을 수 있었겠지.","JPN":"過程はともあれ、あなたは上官の仇を討つことができた。","ENG":"Well, what's done is done. But now, you can avenge your superior.","TWN":"不管過程如何，你都想替長官報仇吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"하지만 나는 아니야. 나에겐 원수를 갚을 기회조차 없었어. 너무 늦어버렸으니까.","JPN":"でも私は違うの。私には仇を討つチャンスすらなかった。すでに手遅れだったのよ。","ENG":"But that's not the case for me. I didn't get my chance for vengeance. I was too late.","TWN":"但我不行，我連報仇的機會都沒有了，已經太遲了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"사실, 이 세상 같은 건 어떻게 되든 상관없어. 이걸로 내 목숨을 잃게 된다고 해도 좋아.","JPN":"本音を言うと、もうこの世界なんてどうなっても構わない。これで自分の命を落としたっていい。","ENG":"Honestly, I don't care what happens to the world. If this is the end for me, so be it.","TWN":"事實上，這個世界怎麼樣都無所謂。即使我因此丟掉性命也沒什麼。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"나는 그저 나를 거둬준 사람에 대한 마지막 의리를 지키고 싶을 뿐이니까.","JPN":"私はただ、私を拾い上げてくれた人に最後の義理を通したいだけなの。","ENG":"But all I want is to pay my respects to the person who took me under his wing.","TWN":"我只是想對當初收留我的人，盡最後一點情義。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAINA_DELTA_NPC_NULL","text":{"KOREA":"그러니까 날 이번 작전에 끼워주지 않겠나, 카린 웡 소령?","JPN":"だから、今回の作戦に私を加えてくれないか、カリン・ウォン少佐？","ENG":"So, will you allow me to join this operation, Major Karin Wong?","TWN":"所以，能不能讓我參與這次作戰呢，卡琳少校？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는…….","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};